// Generates bundler/src/secretQuestionArtifact.ts from the Foundry build output, so that
// POST /deploy works ANYWHERE (Render, a cloner) WITHOUT Foundry on the machine.
//
// Run once after `make build` (and re-run if SecretQuestionAccount.sol changes):
//   node scripts/gen-artifact.js        (from the bundler/ directory)
//
// The generated file is committed so the bundler is self-contained.

const fs = require('fs');
const path = require('path');

const artifactPath = path.resolve(
  __dirname,
  '../../contracts/out/SecretQuestionAccount.sol/SecretQuestionAccount.json',
);

let json;
try {
  json = JSON.parse(fs.readFileSync(artifactPath, 'utf8'));
} catch {
  console.error(`Artifact not found at ${artifactPath} — run \`make build\` first.`);
  process.exit(1);
}

const abi = json.abi;
const bytecode = json.bytecode && json.bytecode.object;
if (!abi || !bytecode) {
  console.error('Missing abi/bytecode in artifact — re-run `make build`.');
  process.exit(1);
}

const content = `// AUTO-GENERATED by scripts/gen-artifact.js — do not edit by hand.
// Embeds the SecretQuestionAccount ABI + creation bytecode so POST /deploy works without Foundry
// (e.g. on Render, or for a cloner who only runs the bundler).
// Regenerate after changing SecretQuestionAccount.sol:  node scripts/gen-artifact.js
import type { Hex } from 'viem';

export const secretQuestionAbi = ${JSON.stringify(abi, null, 2)} as const;

export const secretQuestionBytecode: Hex = '${bytecode}';
`;

const outPath = path.resolve(__dirname, '../src/secretQuestionArtifact.ts');
fs.writeFileSync(outPath, content);
console.log(`Wrote ${outPath}`);
